#!/usr/bin/env python3
"""
Bug #1773: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['constant', 'foldable_sub_zero_div_one'], ['constant', 'mul_self_to_pow'], ['broadcast', 'ceil_unary'], ['broadcast', 'cumsum_last_axis'], ['layout', 'gather_layernorm'], ['branch', 'add_layernorm']]
Dependencies: numpy jax
Run         : python unique_1773.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w1 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w2 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 256])
_w4 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([4, 256])
_w6 = np.frombuffer(bytes.fromhex("00000000"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 256])
_w10 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])
_w11 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([256])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 256])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_fsd_s = x - _w0
    n0_fsd_out = n0_fsd_s / _w1
    n100_msp_sq = n0_fsd_out * n0_fsd_out
    n100_msp_add = n100_msp_sq + _w2
    n100_msp_sq2 = jnp.sqrt(n100_msp_add)
    n100_msp_out = n100_msp_sq2 * _w3
    n200_ceil_a = jnp.ceil(n100_msp_out)
    n200_ceil_out = n200_ceil_a * n100_msp_out
    n300_cs_out = jnp.cumsum(n200_ceil_out, axis=int(_w4.flat[0]))
    n400_gln_gth = jnp.take(_w5, _w6.astype(np.int32), axis=0)
    n400_gln_added = n400_gln_gth + n300_cs_out
    n400_gln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n400_gln_added)) * _w7) + _w8
    n500_aln_add = n400_gln_out + _w9
    n500_aln_out = (((lambda _x: (lambda _m, _v: (_x - _m) / jnp.sqrt(_v + np.float32(9.999999747378752e-06)))(jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True), jnp.mean((_x - jnp.mean(_x, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True))**2, axis=tuple(range(-1%_x.ndim, _x.ndim)), keepdims=True)))(n500_aln_add)) * _w10) + _w11
    return jnp.asarray(n500_aln_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
